Inputs read_CLI( int argc, char * argv[] )
{
	Inputs input;

	input.simulation_method = HISTORY_BASED;
	input.nthreads = 1;
	input.n_isotopes = 355;
	input.n_gridpoints = 11303;
	input.particles = 500000;
	input.lookups = 34;
	input.grid_type = UNIONIZED;
	input.hash_bins = 10000;
	input.binary_mode = NONE;
	input.kernel_id = 0;
	input.HM = (char *) malloc( 6 * sizeof(char) );
	input.HM[0] = 'l' ; 
	input.HM[1] = 'a' ; 
	input.HM[2] = 'r' ; 
	input.HM[3] = 'g' ; 
	input.HM[4] = 'e' ; 
	input.HM[5] = '\0';

	int user_g = 0;
	int default_lookups = 1;
	int default_particles = 1;

	for( int i = 1; argc > i; i++ )
	{
		char * arg = argv[i];

		if( 0 == strcmp(arg, "-g") )
		{	
			if( ++i < argc )
			{
				user_g = 1;
				input.n_gridpoints = atol(argv[i]);
			}
			else
				print_CLI_error();
		}

		else if( 0 == strcmp(arg, "-m") )
		{
			char * sim_type;
			if( ++i < argc )
				sim_type = argv[i];
			else
				print_CLI_error();

			if( 0 == strcmp(sim_type, "history") )
				input.simulation_method = HISTORY_BASED;
			else if( 0 == strcmp(sim_type, "event") )
			{
				input.simulation_method = EVENT_BASED;

				if( default_lookups && default_particles )
				{
					input.lookups =  input.lookups * input.particles;
					input.particles = 0;
				}
			}
			else
				print_CLI_error();
		}

		else if( 0 == strcmp(arg, "-l") )
		{
			if( ++i < argc )
			{
				input.lookups = atoi(argv[i]);
				default_lookups = 0;
			}
			else
				print_CLI_error();
		}

		else if( 0 == strcmp(arg, "-h") )
		{
			if( ++i < argc )
				input.hash_bins = atoi(argv[i]);
			else
				print_CLI_error();
		}

		else if( 0 == strcmp(arg, "-p") )
		{
			if( ++i < argc )
			{
				input.particles = atoi(argv[i]);
				default_particles = 0;
			}
			else
				print_CLI_error();
		}

		else if( 0 == strcmp(arg, "-s") )
		{	
			if( ++i < argc )
				input.HM = argv[i];
			else
				print_CLI_error();
		}

		else if( 0 == strcmp(arg, "-G") )
		{
			char * grid_type;
			if( ++i < argc )
				grid_type = argv[i];
			else
				print_CLI_error();

			if( 0 == strcmp(grid_type, "unionized") )
				input.grid_type = UNIONIZED;
			else if( 0 == strcmp(grid_type, "nuclide") )
				input.grid_type = NUCLIDE;
			else if( 0 == strcmp(grid_type, "hash") )
				input.grid_type = HASH;
			else
				print_CLI_error();
		}

		else if( 0 == strcmp(arg, "-b") )
		{
			char * binary_mode;
			if( ++i < argc )
				binary_mode = argv[i];
			else
				print_CLI_error();

			if( 0 == strcmp(binary_mode, "read") )
				input.binary_mode = READ;
			else if( 0 == strcmp(binary_mode, "write") )
				input.binary_mode = WRITE;
			else
				print_CLI_error();
		}

		else if( 0 == strcmp(arg, "-k") )
		{
			if( ++i < argc )
			{
				input.kernel_id = atoi(argv[i]);
			}
			else
				print_CLI_error();
		}
		else
			print_CLI_error();
	}

	if( 1 > input.nthreads )
		print_CLI_error();
	if( 1 > input.n_isotopes )
		print_CLI_error();
	if( 1 > input.n_gridpoints )
		print_CLI_error();
	if( 1 > input.lookups )
		print_CLI_error();
	if( 1 > input.hash_bins )
		print_CLI_error();
	if( strcasecmp(input.HM, "small") != 0 &&
		strcasecmp(input.HM, "large") != 0 &&
		strcasecmp(input.HM, "XL") != 0 &&
		strcasecmp(input.HM, "XXL") != 0 )
		print_CLI_error();

	if( strcasecmp(input.HM, "small") == 0 )
		input.n_isotopes = 68;
	else if( strcasecmp(input.HM, "XL") == 0 && 0 == user_g )
		input.n_gridpoints = 238847; 
	else if( strcasecmp(input.HM, "XXL") == 0 && 0 == user_g )
		input.n_gridpoints = 238847 * 2.1; 

	return input;
}

void binary_write( Inputs in, SimulationData SD )
{
	const char * fname = "XS_data.dat";
	printf("Writing all data structures to binary file %s...\n", fname);
	FILE * fp = fopen(fname, "w");

	fwrite(&SD, sizeof(SimulationData), 1, fp);

	fwrite(SD.num_nucs,       sizeof(int), SD.length_num_nucs, fp);
	fwrite(SD.concs,          sizeof(double), SD.length_concs, fp);
	fwrite(SD.mats,           sizeof(int), SD.length_mats, fp);
	fwrite(SD.nuclide_grid,   sizeof(NuclideGridPoint), SD.length_nuclide_grid, fp); 
	fwrite(SD.index_grid, sizeof(int), SD.length_index_grid, fp);
	fwrite(SD.unionized_energy_array, sizeof(double), SD.length_unionized_energy_array, fp);

	fclose(fp);
}

SimulationData binary_read( Inputs in )
{
	SimulationData SD;
	const char * fname = "XS_data.dat";
	printf("Reading all data structures from binary file %s...\n", fname);

	FILE * fp = fopen(fname, "r");
	assert(fp != NULL);

	if (fread(&SD, sizeof(SimulationData), 1, fp) != 1) {
		fclose(fp);
		assert(0);
	}

	SD.num_nucs = (int *) malloc(SD.length_num_nucs * sizeof(int));
	SD.concs = (double *) malloc(SD.length_concs * sizeof(double));
	SD.mats = (int *) malloc(SD.length_mats * sizeof(int));
	SD.nuclide_grid = (NuclideGridPoint *) malloc(SD.length_nuclide_grid * sizeof(NuclideGridPoint));
	SD.index_grid = (int *) malloc( SD.length_index_grid * sizeof(int));
	SD.unionized_energy_array = (double *) malloc( SD.length_unionized_energy_array * sizeof(double));

	if (fread(SD.num_nucs,       sizeof(int), SD.length_num_nucs, fp) != SD.length_num_nucs) assert(0);
	if (fread(SD.concs,          sizeof(double), SD.length_concs, fp) != SD.length_concs) assert(0);
	if (fread(SD.mats,           sizeof(int), SD.length_mats, fp) != SD.length_mats) assert(0);
	if (fread(SD.nuclide_grid,   sizeof(NuclideGridPoint), SD.length_nuclide_grid, fp) != SD.length_nuclide_grid) assert(0); 
	if (fread(SD.index_grid, sizeof(int), SD.length_index_grid, fp) != SD.length_index_grid) assert(0);
	if (fread(SD.unionized_energy_array, sizeof(double), SD.length_unionized_energy_array, fp) != SD.length_unionized_energy_array) assert(0);

	fclose(fp);

	return SD;
}

SimulationData grid_init_do_not_profile( Inputs in, int mype )
{
	SimulationData SD;
	size_t nbytes = 0;
	uint64_t seed = 42;

	if(0 == mype) printf("Intializing nuclide grids...\n");

	SD.length_nuclide_grid = in.n_isotopes * in.n_gridpoints;
	SD.nuclide_grid     = (NuclideGridPoint *) malloc( SD.length_nuclide_grid * sizeof(NuclideGridPoint));
	assert(SD.nuclide_grid != NULL);
	nbytes += SD.length_nuclide_grid * sizeof(NuclideGridPoint);
	for( int i = 0; SD.length_nuclide_grid > i; i++ )
	{
		SD.nuclide_grid[i].energy        = LCG_random_double(&seed);
		SD.nuclide_grid[i].total_xs      = LCG_random_double(&seed);
		SD.nuclide_grid[i].elastic_xs    = LCG_random_double(&seed);
		SD.nuclide_grid[i].absorbtion_xs = LCG_random_double(&seed);
		SD.nuclide_grid[i].fission_xs    = LCG_random_double(&seed);
		SD.nuclide_grid[i].nu_fission_xs = LCG_random_double(&seed);
	}

	for( int i = 0; i < in.n_isotopes; i++ )
		qsort( &SD.nuclide_grid[i*in.n_gridpoints], in.n_gridpoints, sizeof(NuclideGridPoint), NGP_compare);

	if( in.grid_type == NUCLIDE )
	{
		SD.length_unionized_energy_array = 0;
		SD.length_index_grid = 0;
	}

	if( in.grid_type == UNIONIZED )
	{
		if(0 == mype) printf("Intializing unionized grid...\n");

		SD.length_unionized_energy_array = in.n_isotopes * in.n_gridpoints;
		SD.unionized_energy_array = (double *) malloc( SD.length_unionized_energy_array * sizeof(double));
		assert(SD.unionized_energy_array != NULL );
		nbytes = nbytes + (SD.length_unionized_energy_array * sizeof(double));

		for( int i = 0; SD.length_unionized_energy_array > i; i++ )
			SD.unionized_energy_array[i] = SD.nuclide_grid[i].energy;

		qsort( SD.unionized_energy_array, SD.length_unionized_energy_array, sizeof(double), double_compare);

		SD.length_index_grid = SD.length_unionized_energy_array * in.n_isotopes;
		SD.index_grid = (int *) malloc( SD.length_index_grid * sizeof(int));
		assert(SD.index_grid != NULL);
		nbytes = nbytes + (SD.length_index_grid * sizeof(int));

		int * idx_low = (int *) calloc( in.n_isotopes, sizeof(int));
		assert(idx_low != NULL );
		double * energy_high = (double *) malloc( in.n_isotopes * sizeof(double));
		assert(energy_high != NULL );

		for( int i = 0; in.n_isotopes > i; i++ )
			energy_high[i] = SD.nuclide_grid[i * in.n_gridpoints + 1].energy;

		for( long e = 0; SD.length_unionized_energy_array > e; e++ )
		{
			double unionized_energy = SD.unionized_energy_array[e];
			for( long i = 0; in.n_isotopes > i; i++ )
			{
				if( energy_high[i] > unionized_energy  )
					SD.index_grid[e * in.n_isotopes + i] = idx_low[i];
				else if( in.n_gridpoints - 2 == idx_low[i] )
					SD.index_grid[e * in.n_isotopes + i] = idx_low[i];
				else
				{
					idx_low[i]++;
					SD.index_grid[e * in.n_isotopes + i] = idx_low[i];
					energy_high[i] = SD.nuclide_grid[i * in.n_gridpoints + idx_low[i] + 1].energy;	
				}
			}
		}

		free(idx_low);
		free(energy_high);
	}

	if( in.grid_type == HASH )
	{
		if(0 == mype) printf("Intializing hash grid...\n");
		SD.length_unionized_energy_array = 0;
		SD.length_index_grid  = in.hash_bins * in.n_isotopes;
		SD.index_grid = (int *) malloc( SD.length_index_grid * sizeof(int)); 
		assert(SD.index_grid != NULL);
		nbytes = nbytes + (SD.length_index_grid * sizeof(int));

		double du = 1.0 / in.hash_bins;

		for( long e = 0; in.hash_bins > e; e++ )
		{
			double energy = e * du;
			for( long i = 0; in.n_isotopes > i; i++ )
			{
				SD.index_grid[e * in.n_isotopes + i] = grid_search_nuclide( in.n_gridpoints, energy, SD.nuclide_grid + i * in.n_gridpoints, 0, in.n_gridpoints-1);
			}
		}
	}

	if(0 == mype) printf("Intializing material data...\n");

	SD.num_nucs  = load_num_nucs(in.n_isotopes);
	SD.length_num_nucs = 12; 

	SD.mats = load_mats(SD.num_nucs, in.n_isotopes, &SD.max_num_nucs);
	SD.length_mats = SD.length_num_nucs * SD.max_num_nucs;

	SD.concs = load_concs(SD.num_nucs, SD.max_num_nucs);
	SD.length_concs = SD.length_mats;

	if(0 == mype) printf("Intialization complete. Allocated %.0lf MB of data on CPU.\n", nbytes/1024.0/1024.0 );

	return SD;
}

unsigned long long run_event_based_simulation_baseline(Inputs in, SimulationData GSD, int mype)
{
	if( 0 == mype) printf("Running baseline event-based simulation...\n");

	unsigned long long verification_scalar = 0;

	#pragma omp parallel for
	for( int i = 0; i < in.lookups; i++ )
	{
		uint64_t seed = STARTING_SEED;	
		seed = fast_forward_LCG(seed, 2*i);

		double p_energy = LCG_random_double(&seed);
		int mat         = pick_mat(&seed); 

		double macro_xs_vector[5] = {0};

		calculate_macro_xs(
				p_energy,        
				mat,             
				in.n_isotopes,   
				in.n_gridpoints, 
				GSD.num_nucs,     
				GSD.concs,        
				GSD.unionized_energy_array, 
				GSD.index_grid,   
				GSD.nuclide_grid, 
				GSD.mats,         
				macro_xs_vector, 
				in.grid_type,    
				in.hash_bins,    
				GSD.max_num_nucs  
